--- a/src/parseTags.ts
+++ b/src/parseTags.ts
@@ -1,3 +1,3 @@
 export function parseTags(input: string): string[] {
-  return input.split(",");
+  return [...new Set(input.split(",").map((tag) => tag.trim()).filter(Boolean))];
 }
--- a/tests/parseTags.test.ts
+++ b/tests/parseTags.test.ts
@@ -3,7 +3,13 @@
 import { parseTags } from "../src/parseTags";

 describe("parseTags", () => {
-  it("splits ordinary comma-separated tags", () => {
+  it("normalizes ordinary comma-separated tags", () => {
     expect(parseTags("alpha,beta")).toEqual(["alpha", "beta"]);
   });
+
+  it("handles empty, repeated separator, whitespace-only, and duplicate cases", () => {
+    expect(parseTags("")).toEqual([]);
+    expect(parseTags("alpha,, beta, alpha,   " )).toEqual(["alpha", "beta"]);
+    expect(parseTags("   , ")).toEqual([]);
+  });
 });
